from redis.commands.search.field import VectorField, TagField
from redis.commands.search.indexDefinition import IndexDefinition, IndexType

def create_index(dim: int = 1536) -> None:
    try:
        r.ft("chunks_idx").info()
        return  # already exists
    except Exception:
        pass

    schema = (
        TagField("$.tenant_id", as_name="tenant_id"),
        VectorField(
            "embedding",
            "HNSW",
            {
                "TYPE": "FLOAT32",
                "DIM": dim,
                "DISTANCE_METRIC": "COSINE",
                "M": 16,
                "EF_CONSTRUCTION": 200,
            },
        ),
    )
    r.ft("chunks_idx").create_index(
        schema,
        definition=IndexDefinition(prefix=["chunk:"], index_type=IndexType.JSON),
    )

def search_atlas(
    query_embedding: list[float],
    tenant_id: str,
    lang: str = "en",
    top_k: int = 10,
) -> list[dict]:
    pipeline = [
        {
            "$vectorSearch": {
                "index": "chunks_vector_idx",
                "path": "embedding",
                "queryVector": query_embedding,
                "numCandidates": top_k * 10,   # overretrieve for post-filter
                "limit": top_k,
                "filter": {
                    "tenant_id": {"$eq": tenant_id},
                    "lang": {"$eq": lang},
                },
            }
        },
        {
            "$project": {
                "_id": 0,
                "content": 1,
                "doc_id": 1,
                "score": {"$meta": "vectorSearchScore"},
            }
        },
    ]
    return list(chunks.aggregate(pipeline))

