import boto3, json
from requests_aws4auth import AWS4Auth
import requests

def search_opensearch(query_embedding, tenant_id, top_k=10):
    auth = AWS4Auth(...)  # from botocore credentials
    payload = {
        "size": top_k,
        "query": {
            "bool": {
                "filter": [{"term": {"tenant_id": tenant_id}}],
                "must": [{
                    "knn": {
                        "embedding": {
                            "vector": query_embedding,
                            "k": top_k,
                        }
                    }
                }]
            }
        }
    }
    resp = requests.post(
        "https://<endpoint>.aoss.amazonaws.com/chunks/_search",
        auth=auth,
        json=payload,
    )
    hits = resp.json()["hits"]["hits"]
    return [{"content": h["_source"]["content"], "score": h["_score"]} for h in hits]
